#[test]
fn test_spectral_kpoint_path_multiple_entries() {
    let rows = vec![
        CellValue::Array(vec![
            CellValue::Float(0.3333333333),
            CellValue::Float(0.375),
            CellValue::Float(0.3333333333),
        ]),
        CellValue::Array(vec![
            CellValue::Float(0.3333333333),
            CellValue::Float(0.375),
            CellValue::Float(0.0),
        ]),
    ];
    let result = SpectralKpointPath::from_block_rows(&rows).unwrap();
    assert_eq!(result.points.len(), 2);
}

#[test]
fn test_spectral_kpoints_list_multiple_entries() {
    let rows = vec![
        CellValue::Array(vec![
            CellValue::Float(0.0),
            CellValue::Float(0.0),
            CellValue::Float(0.0),
            CellValue::Float(0.25),
        ]),
        CellValue::Array(vec![
            CellValue::Float(0.5),
            CellValue::Float(0.0),
            CellValue::Float(0.0),
            CellValue::Float(0.75),
        ]),
    ];
    let result = SpectralKpointsList::from_block_rows(&rows).unwrap();
    assert_eq!(result.kpts.len(), 2);
    assert_eq!(result.kpts[0].weight, 0.25);
}

#[test]
fn test_spectral_kpoint_path_spacing_with_unit() {
    let value = CellValue::Array(vec![
        CellValue::Float(0.05),
        CellValue::Str("1/ang"),
    ]);
    let result = SpectralKpointPathSpacing::from_cell_value(&value).unwrap();
    assert_eq!(result.value, 0.05);
    assert!(result.unit.is_some());
}

#[test]
fn test_spectral_kpoints_mp_grid_from_cell_value() {
    let val = CellValue::Array(vec![
        CellValue::UInt(3),
        CellValue::UInt(4),
        CellValue::UInt(6),
    ]);
    let grid = SpectralKpointsMpGrid::from_cell_value(&val).unwrap();
    assert_eq!(grid.0, [3, 4, 6]);
}

#[test]
fn test_spectral_kpoints_mp_spacing_scalar() {
    let value = CellValue::Float(0.05);
    let result = SpectralKpointsMpSpacing::from_cell_value(&value).unwrap();
    assert_eq!(result.value, 0.05);
    assert_eq!(result.unit, None);
}

#[test]
fn test_spectral_kpoints_mp_offset_from_cell_value() {
    let val = CellValue::Array(vec![
        CellValue::Float(0.0),
        CellValue::Float(0.5),
        CellValue::Float(0.5),
    ]);
    let offset = SpectralKpointsMpOffset::from_cell_value(&val).unwrap();
    assert_eq!(offset.0, [0.0, 0.5, 0.5]);
}
